import React, { useState, useEffect } from 'react';
import { useNavigate } from 'react-router-dom';
import { authAPI } from '../services/api';

const Dashboard = () => {
  const [stats, setStats] = useState({
    lessonsCompleted: 0,
    practiceSessionsCompleted: 0,
    avgWPM: 0,
    avgAccuracy: 0
  });
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState(null);
  const navigate = useNavigate();

  useEffect(() => {
    fetchDashboardStats();
  }, []);

  const fetchDashboardStats = async () => {
    try {
      const response = await authAPI.getDashboard();
      setStats(response.data);
    } catch (err) {
      console.error('Error fetching dashboard stats:', err);
      setError('Failed to load dashboard statistics');
    } finally {
      setLoading(false);
    }
  };

  if (loading) {
    return <div className="loading">Loading dashboard...</div>;
  }

  return (
    <div className="container">
      <div className="dashboard">
        <h2>Your Progress Dashboard</h2>

        {error && <div className="error">{error}</div>}

        <div className="stats-grid">
          <div className="stat-card">
            <h3>{stats.lessonsCompleted}</h3>
            <p>Lessons Completed</p>
          </div>
          <div className="stat-card">
            <h3>{stats.practiceSessionsCompleted}</h3>
            <p>Practice Sessions</p>
          </div>
          <div className="stat-card">
            <h3>{stats.avgWPM}</h3>
            <p>Average WPM</p>
          </div>
          <div className="stat-card">
            <h3>{stats.avgAccuracy}%</h3>
            <p>Average Accuracy</p>
          </div>
        </div>

        <div className="mode-selection">
          <div className="mode-card" onClick={() => navigate('/learn')}>
            <h3>📚 Learn Mode</h3>
            <p>
              Progress through structured lessons starting from home row basics 
              to advanced typing. Each chapter builds on the previous one with 
              carefully designed exercises.
            </p>
            <button className="btn btn-primary" style={{ marginTop: '1rem', width: '100%' }}>
              Start Learning
            </button>
          </div>

          <div className="mode-card" onClick={() => navigate('/practice')}>
            <h3>💪 Practice Mode</h3>
            <p>
              Test your skills with timed practice sessions. Choose from 10 
              different sessions designed to improve your speed and accuracy 
              with real-world typing scenarios.
            </p>
            <button className="btn btn-secondary" style={{ marginTop: '1rem', width: '100%' }}>
              Start Practicing
            </button>
          </div>
        </div>

        <div style={{ marginTop: '2rem', textAlign: 'center' }}>
          <button 
            className="btn" 
            style={{ background: '#ff6b6b', color: 'white' }}
            onClick={() => navigate('/admin')}
          >
            🔧 Admin Panel (Manage Content)
          </button>
          <p style={{ fontSize: '0.85rem', color: '#666', marginTop: '0.5rem' }}>
            Access with admin account
          </p>
        </div>
      </div>
    </div>
  );
};

export default Dashboard;
